css:
.loader {
  display: inline-block;
  width: 62px;
  height: 62px;
  border-radius: 50%;
  border: 4px solid color-mix(in srgb, var(--loader-color) 18%, transparent);
  border-top-color: var(--loader-color);
  animation: spin 1.1099999999999999s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }
